import { useState } from "react";
import axios from "axios";

function Chatbot() {

    const [question, setQuestion] = useState("");
    const [response, setResponse] = useState("");

    const handleSend = async () => {

        if (question.toLowerCase().includes("weather") || question.toLowerCase().includes("climate")) {

            try {

                const res = await axios.get(
                    "https://api.open-meteo.com/v1/forecast?latitude=11.0168&longitude=76.9558&current_weather=true"
                );

                const temp = res.data.current_weather.temperature;

                setResponse(`Today's temperature is ${temp}°C. Climate conditions are stable.`);

            } catch (error) {

                setResponse("Unable to fetch weather data.");

            }

        } else {

            setResponse("Please ask about climate or weather.");

        }

    };

    return (
        <div className="page">

            <h1>AI Climate Chatbot</h1>

            <p>Ask about climate, weather, or sustainability.</p>

            <div style={{ marginTop: "20px" }}>
                <input
                    type="text"
                    placeholder="Ask climate question"
                    value={question}
                    onChange={(e) => setQuestion(e.target.value)}
                />

                <button onClick={handleSend}>Send</button>
            </div>

            <div style={{ marginTop: "30px" }}>
                <h3>{response}</h3>
            </div>

        </div>
    );
}

export default Chatbot;
